import { useNavigate } from 'react-router-dom';
import CustomButton from '../components/CustomButton';

import "../styles/Home.css";

function GameButton() {
    const navigate = useNavigate();
  
    return (
      <>
      <h1>Hola</h1>
        <CustomButton
          buttonLabel={"game"}
          onClick={() => navigate('/game')}
        />
      </>
    );
  }

  function Home(){
    
    return <>
    <GameButton/>
    </>
  }

  export default Home;
